// Compose daily digest from ELK + GlitchTip data
const items = $input.all();
let elkData = items[0]?.json || {};
let glitchtipData = items[1]?.json || {};
const warnings = [];

// Detect continueOnFail error items
if (elkData.error || elkData.$error) {
  warnings.push('ELK query failed: ' + (elkData.error?.message || elkData.$error?.message || 'Unknown error'));
  elkData = {};
}
if (glitchtipData.error || glitchtipData.$error) {
  warnings.push('GlitchTip query failed: ' + (glitchtipData.error?.message || glitchtipData.$error?.message || 'Unknown error'));
  glitchtipData = {};
}

const today = new Date().toISOString().split('T')[0];

// Parse ELK aggregations
const aggs = elkData.aggregations || {};
const totalErrors = aggs.total_errors?.value || 0;
const byHost = (aggs.by_host?.buckets || []).map(b => `  - **${b.key}**: ${b.doc_count} errors`).join('\n');
const byService = (aggs.by_service?.buckets || []).map(b => `  - **${b.key}**: ${b.doc_count} errors`).join('\n');
const byLevel = (aggs.by_level?.buckets || []).map(b => `  - **${b.key}**: ${b.doc_count}`).join('\n');
const topErrors = (aggs.top_errors?.buckets || []).slice(0, 5).map(b => `  - \`${b.key.substring(0, 100)}\` (${b.doc_count}x)`).join('\n');

// Detect affected services for labels
const SVC_LABEL_MAP = {
  'mcphub': 'svc:mcphub', 'grafana': 'svc:grafana', 'prometheus': 'svc:grafana',
  'elasticsearch': 'svc:elk', 'logstash': 'svc:elk', 'kibana': 'svc:elk',
  'web': 'svc:glitchtip', 'worker': 'svc:glitchtip', 'redis': 'svc:glitchtip',
  'n8n': 'svc:n8n', 'blacklist-app': 'svc:blacklist', 'blacklist-collector': 'svc:blacklist'
};
const detectedServices = new Set();
for (const bucket of (aggs.by_service?.buckets || [])) {
  const svcLabel = SVC_LABEL_MAP[bucket.key];
  if (svcLabel) detectedServices.add(svcLabel);
}
const labels = ['digest', 'automated', ...detectedServices];

// Check for blacklist-related errors
const blacklistErrors = (aggs.by_service?.buckets || []).filter(b => b.key.includes('blacklist'));
const blacklistNote = blacklistErrors.length > 0 ? `\n\n> Warning: **Blacklist service errors detected** (${blacklistErrors.reduce((s, b) => s + b.doc_count, 0)} errors) - see [qws941/blacklist](https://github.com/qws941/blacklist)` : '';

// Parse GlitchTip issues
const issues = Array.isArray(glitchtipData) ? glitchtipData : (glitchtipData.results || []);
const unresolvedCount = issues.length;
const issueList = issues.slice(0, 10).map(i => `  - [${i.title || i.metadata?.type || 'Unknown'}](http://192.168.50.106:8000) (${i.count || 1}x)`).join('\n');

// Warnings section
const warningSection = warnings.length > 0 ? `\n\n### Data Source Warnings\n${warnings.map(w => `  - ${w}`).join('\n')}` : '';

const body = `## Daily Infrastructure Digest - ${today}${warningSection}\n\n### ELK Log Summary (Last 24h)\n\n**Total Errors**: ${totalErrors}\n\n#### Errors by Host\n${byHost || '  - No errors detected'}\n\n#### Errors by Service\n${byService || '  - No service data'}\n\n#### Errors by Level\n${byLevel || '  - No level data'}\n\n#### Top Error Messages\n${topErrors || '  - None'}${blacklistNote}\n\n---\n\n### GlitchTip - Unresolved Issues\n\n**Count**: ${unresolvedCount}\n\n${issueList || '  - No unresolved issues'}\n\n---\n\n### Action Items\n\n- [ ] Review hosts with highest error counts\n- [ ] Triage new GlitchTip issues\n- [ ] Check alert history in Grafana`;

return [{ json: { title: `[Daily Digest] ${today} Infrastructure Summary (${totalErrors} errors)`, body, date: today, totalErrors, unresolvedCount, labels } }];
